import os
import sys

def get_platform():
    os_platform = sys.platform
    if os_platform.startswith("win"):
        return "win"
    elif os_platform.startswith("mac"):
        return "mac"
    else:
        return "nix"

def add_common_path(lib) :
    if (sys.version_info[0] > 3) or ((sys.version_info[0] == 3) and (sys.version_info[1] >= 8)) :
        if get_platform() == "win" :
            bin_dir = os.path.join(os.getenv("CommonProgramFiles"), "Quanser", "bin")
            if os.path.exists(bin_dir) == True :
                os.add_dll_directory(bin_dir)
                return os.path.join(bin_dir, lib)
            else :
                return lib
        else :
            return lib
